{
  "name": "SocialGenius - HK",
  "description": "Professional content generator for XiaoHongShu and Instagram, tailored for HK and Mainland markets."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Platform = 'xhs' | 'ig';

export interface StoreAddress {
  id: string;
  name: string;
  detail: string;
  isSelected: boolean;
}

export interface AppState {
  topic: string;
  platforms: Platform[];
  bio: string;
  addresses: StoreAddress[];
}

export interface GeneratedContent {
  platform: Platform;
  content: string;
  loading: boolean;
  error?: string;
}

export const DEFAULT_BIO = "專注於提供高品質的生活方式解決方案，為您的日常增添質感。";

export const DEFAULT_ADDRESSES: StoreAddress[] = [
  { id: '1', name: '銅鑼灣旗艦店', detail: '銅鑼灣軒尼詩道500號希慎廣場12樓', isSelected: true },
  { id: '2', name: '尖沙咀分店', detail: '尖沙咀廣東道3-27號海港城海運大廈2樓', isSelected: false },
  { id: '3', name: '旺角分店', detail: '旺角亞皆老街8號朗豪坊5樓', isSelected: false },
];

import { GoogleGenAI } from "@google/genai";
import { Platform, StoreAddress } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-3-flash-preview";

const generatePrompt = (
  platform: Platform, 
  topic: string, 
  bio: string, 
  selectedAddresses: StoreAddress[]
): string => {
  const addressList = selectedAddresses.length > 0 
    ? selectedAddresses.map(a => `${a.name}: ${a.detail}`).join('\n')
    : "不顯示地址 (No address selected)";

  if (platform === 'xhs') {
    return `
      你是一個頂級的小紅書內容創作者（KOL）。請根據以下要求撰寫一篇爆款筆記。

      **核心任務：**
      主題：${topic}

      **品牌資訊（必須包含）：**
      1. 個人/品牌簡介：${bio}
      2. 店鋪地址：
      ${addressList}

      **小紅書模式規則 (XHS Mode)：**
      1. **語言**：使用簡體中文 (Simplified Chinese)。
      2. **語氣**：親切、真實、像閨蜜分享（家人們、集美們、絕絕子、寶藏）。使用大量 Emoji 🤩✨。
      3. **內容結構**：
         - **標題**：極具吸引力，使用爆款關鍵詞（如：必看、後悔沒早買、親測有效），加上 Emoji。
         - **正文**：
           - **痛點切入**：第一段必須點出用戶的痛點或焦慮。
           - **乾貨/解決方案**：提供極其專業、高品質的內容或產品優勢。
           - **品牌植入**：自然地融入上述的個人簡介和選定的店鋪地址。
         - **標籤**：文末添加 5-10 個熱門話題標籤 (#)。
      4. **排版**：分段清晰，善用 Emoji 作為列表符號。

      **輸出格式要求：**
      請直接輸出最終的筆記內容（包括標題），不要包含任何解釋性文字。
    `;
  } else {
    return `
      你是一個專業的 Instagram 社交媒體經理。請根據以下要求撰寫一個高互動率的 Post。

      **核心任務：**
      主題：${topic}

      **品牌資訊（必須包含）：**
      1. 個人/品牌簡介：${bio}
      2. 店鋪地址：
      ${addressList}

      **Instagram 模式規則 (IG Mode)：**
      1. **語言**：使用繁體中文 (Traditional Chinese)，符合香港 (Hong Kong) 用語習慣。
      2. **語氣**：專業、有質感、針對痛點但保持優雅。
      3. **內容結構**：
         - **Hook (首句)**：一句話抓住注意力，直擊讀者需求。
         - **Body (正文)**：
           - 深入淺出地分析問題（痛點）。
           - 提供專業的解決方案或價值。
         - **CTA (行動呼籲) & 資訊**：
           - 包含上述的個人簡介。
           - 包含選定的店鋪地址（排版要整齊）。
           - 引導讀者 Save 低、Share 俾朋友或留言。
         - **Hashtags**：文末添加 15-20 個相關且高流量的標籤，並以點點點分隔開正文。
      4. **排版**：極簡風格，善用空行增加易讀性。

      **輸出格式要求：**
      請直接輸出最終的貼文內容，不要包含任何解釋性文字。
    `;
  }
};

export const generatePostContent = async (
  platform: Platform,
  topic: string,
  bio: string,
  addresses: StoreAddress[]
): Promise<string> => {
  try {
    const selectedAddresses = addresses.filter(a => a.isSelected);
    const prompt = generatePrompt(platform, topic, bio, selectedAddresses);

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        temperature: 0.8, // Slightly creative
        topK: 40,
        topP: 0.95,
      }
    });

    return response.text || "生成內容時發生錯誤，請重試。";
  } catch (error) {
    console.error(`Error generating content for ${platform}:`, error);
    throw new Error(`無法生成 ${platform === 'xhs' ? '小紅書' : 'Instagram'} 內容。請檢查網絡或稍後再試。`);
  }
};

import React, { useState } from 'react';
import { StoreAddress } from '../types';

interface SettingsPanelProps {
  bio: string;
  setBio: (val: string) => void;
  addresses: StoreAddress[];
  setAddresses: (val: StoreAddress[]) => void;
}

const SettingsPanel: React.FC<SettingsPanelProps> = ({ bio, setBio, addresses, setAddresses }) => {
  const [newAddressName, setNewAddressName] = useState('');
  const [newAddressDetail, setNewAddressDetail] = useState('');

  const toggleAddress = (id: string) => {
    setAddresses(addresses.map(addr => 
      addr.id === id ? { ...addr, isSelected: !addr.isSelected } : addr
    ));
  };

  const removeAddress = (id: string) => {
    setAddresses(addresses.filter(addr => addr.id !== id));
  };

  const addNewAddress = () => {
    if (!newAddressName.trim() || !newAddressDetail.trim()) return;
    const newAddr: StoreAddress = {
      id: Date.now().toString(),
      name: newAddressName,
      detail: newAddressDetail,
      isSelected: true
    };
    setAddresses([...addresses, newAddr]);
    setNewAddressName('');
    setNewAddressDetail('');
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 space-y-6">
      <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
        <span>⚙️</span> 品牌設定 (Brand Setup)
      </h2>

      {/* Bio Section */}
      <div>
        <label className="block text-sm font-medium text-slate-700 mb-2">
          品牌/個人簡介 (Bio)
        </label>
        <textarea
          value={bio}
          onChange={(e) => setBio(e.target.value)}
          rows={3}
          className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition resize-none text-sm"
          placeholder="輸入您的品牌簡介..."
        />
        <p className="text-xs text-slate-500 mt-1">此簡介將會被自動整合到生成的貼文中。</p>
      </div>

      {/* Address Section */}
      <div>
        <label className="block text-sm font-medium text-slate-700 mb-3">
          分店地址 (Store Addresses)
        </label>

        <div className="space-y-3 mb-4 max-h-60 overflow-y-auto pr-1">
          {addresses.map((addr) => (
            <div 
              key={addr.id} 
              className={`flex items-start gap-3 p-3 rounded-lg border cursor-pointer transition-all ${
                addr.isSelected 
                  ? 'bg-purple-50 border-purple-400' 
                  : 'bg-slate-50 border-slate-200 hover:border-slate-300'
              }`}
              onClick={() => toggleAddress(addr.id)}
            >
              <div className={`mt-1 w-5 h-5 rounded border flex items-center justify-center flex-shrink-0 ${
                addr.isSelected ? 'bg-purple-600 border-purple-600' : 'bg-white border-slate-400'
              }`}>
                {addr.isSelected && (
                  <svg className="w-3.5 h-3.5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                )}
              </div>
              <div className="flex-1">
                <div className="font-semibold text-slate-800 text-sm">{addr.name}</div>
                <div className="text-xs text-slate-500 mt-0.5">{addr.detail}</div>
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); removeAddress(addr.id); }}
                className="text-slate-400 hover:text-red-500 p-1"
                title="移除地址"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
              </button>
            </div>
          ))}
          {addresses.length === 0 && (
            <div className="text-center py-4 text-slate-400 text-sm italic">
              暫無地址，請新增。
            </div>
          )}
        </div>

        {/* Add New Address */}
        <div className="flex flex-col gap-2 pt-3 border-t border-slate-100">
          <input 
            type="text" 
            placeholder="分店名稱 (e.g., 銅鑼灣店)" 
            value={newAddressName}
            onChange={(e) => setNewAddressName(e.target.value)}
            className="px-3 py-2 border border-slate-300 rounded text-sm focus:outline-none focus:border-purple-500"
          />
          <input 
            type="text" 
            placeholder="詳細地址" 
            value={newAddressDetail}
            onChange={(e) => setNewAddressDetail(e.target.value)}
            className="px-3 py-2 border border-slate-300 rounded text-sm focus:outline-none focus:border-purple-500"
          />
          <button 
            onClick={addNewAddress}
            disabled={!newAddressName || !newAddressDetail}
            className="bg-slate-800 text-white text-sm py-2 rounded hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed transition"
          >
            + 新增地址
          </button>
        </div>
      </div>
    </div>
  );
};

export default SettingsPanel;

import React, { useState } from 'react';
import { GeneratedContent } from '../types';

interface OutputCardProps {
  data: GeneratedContent;
}

const OutputCard: React.FC<OutputCardProps> = ({ data }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(data.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const isXHS = data.platform === 'xhs';
  const bgColor = isXHS ? 'bg-red-50' : 'bg-gradient-to-tr from-purple-50 to-orange-50';
  const borderColor = isXHS ? 'border-red-100' : 'border-purple-100';
  const titleColor = isXHS ? 'text-red-600' : 'text-purple-600';
  const icon = isXHS ? '📕' : '📸';
  const title = isXHS ? '小紅書 (Red Note)' : 'Instagram';

  return (
    <div className={`rounded-xl border ${borderColor} ${bgColor} overflow-hidden flex flex-col h-full shadow-sm`}>
      <div className="px-5 py-4 border-b border-white/50 flex justify-between items-center bg-white/50 backdrop-blur-sm">
        <h3 className={`font-bold ${titleColor} flex items-center gap-2`}>
          <span>{icon}</span> {title}
        </h3>
        <button
          onClick={handleCopy}
          className={`text-xs font-medium px-3 py-1.5 rounded-full transition flex items-center gap-1 ${
            copied 
              ? 'bg-green-100 text-green-700' 
              : 'bg-white hover:bg-slate-100 text-slate-600 border border-slate-200'
          }`}
        >
          {copied ? (
            <>
              <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
              已複製
            </>
          ) : (
            <>
              <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3"></path></svg>
              複製內容
            </>
          )}
        </button>
      </div>

      <div className="p-5 flex-1 overflow-y-auto min-h-[300px] max-h-[500px]">
        {data.loading ? (
          <div className="h-full flex flex-col items-center justify-center space-y-3 opacity-60">
            <div className={`w-8 h-8 border-4 ${isXHS ? 'border-red-400' : 'border-purple-400'} border-t-transparent rounded-full animate-spin`}></div>
            <p className="text-sm font-medium animate-pulse">正在生成專業貼文...</p>
          </div>
        ) : data.error ? (
           <div className="h-full flex flex-col items-center justify-center text-red-500 p-4 text-center">
            <svg className="w-8 h-8 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
            <p className="text-sm">{data.error}</p>
          </div>
        ) : (
          <div className="prose prose-sm max-w-none whitespace-pre-wrap font-sans text-slate-700 leading-relaxed">
            {data.content}
          </div>
        )}
      </div>
    </div>
  );
};

export default OutputCard;

import React, { useState } from 'react';
import { Platform, StoreAddress, GeneratedContent, DEFAULT_BIO, DEFAULT_ADDRESSES } from './types';
import SettingsPanel from './components/SettingsPanel';
import OutputCard from './components/OutputCard';
import { generatePostContent } from './services/geminiService';

const App: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [selectedPlatforms, setSelectedPlatforms] = useState<Platform[]>(['xhs']);
  const [bio, setBio] = useState(DEFAULT_BIO);
  const [addresses, setAddresses] = useState<StoreAddress[]>(DEFAULT_ADDRESSES);

  const [results, setResults] = useState<{ xhs?: GeneratedContent; ig?: GeneratedContent }>({});
  const [isGenerating, setIsGenerating] = useState(false);

  const togglePlatform = (p: Platform) => {
    setSelectedPlatforms(prev => 
      prev.includes(p) ? prev.filter(x => x !== p) : [...prev, p]
    );
  };

  const handleGenerate = async () => {
    if (!topic.trim()) return;
    if (selectedPlatforms.length === 0) return;

    setIsGenerating(true);

    // Initialize loading states
    const initialResults: { xhs?: GeneratedContent; ig?: GeneratedContent } = {};
    if (selectedPlatforms.includes('xhs')) {
      initialResults.xhs = { platform: 'xhs', content: '', loading: true };
    }
    if (selectedPlatforms.includes('ig')) {
      initialResults.ig = { platform: 'ig', content: '', loading: true };
    }
    setResults(initialResults);

    // Create promises for parallel execution
    const promises = selectedPlatforms.map(async (platform) => {
      try {
        const content = await generatePostContent(platform, topic, bio, addresses);
        setResults(prev => ({
          ...prev,
          [platform]: { platform, content, loading: false }
        }));
      } catch (e: any) {
        setResults(prev => ({
          ...prev,
          [platform]: { platform, content: '', loading: false, error: e.message || 'Error' }
        }));
      }
    });

    await Promise.all(promises);
    setIsGenerating(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-gradient-to-br from-purple-600 to-pink-500 rounded-lg flex items-center justify-center text-white font-bold text-lg">
              S
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-800 to-slate-600">
              SocialGenius
            </h1>
          </div>
          <div className="text-xs font-medium px-3 py-1 bg-slate-100 rounded-full text-slate-500">
            Preview v1.0
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* LEFT COLUMN: Controls */}
          <div className="lg:col-span-5 space-y-6">

            {/* Input Card */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 space-y-6">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <span>📝</span> 貼文內容 (Content)
              </h2>

              {/* Topic Input */}
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">
                  貼文主題 / 產品賣點
                </label>
                <textarea
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  rows={4}
                  className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition text-base"
                  placeholder="例如：夏季最新款防曬乳，不黏膩，美白效果..."
                />
              </div>

              {/* Platform Selector */}
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-3">
                  選擇平台模式 (Select Modes)
                </label>
                <div className="grid grid-cols-2 gap-4">
                  <button
                    onClick={() => togglePlatform('xhs')}
                    className={`relative p-4 rounded-xl border-2 transition-all flex flex-col items-center gap-2 ${
                      selectedPlatforms.includes('xhs')
                        ? 'border-red-500 bg-red-50 text-red-700'
                        : 'border-slate-200 hover:border-slate-300 text-slate-500'
                    }`}
                  >
                     <span className="text-2xl">📕</span>
                     <span className="font-bold text-sm">小紅書模式</span>
                     <span className="text-[10px] opacity-70">簡體 · 內地語氣</span>
                     {selectedPlatforms.includes('xhs') && (
                       <div className="absolute top-2 right-2 w-2 h-2 rounded-full bg-red-500"></div>
                     )}
                  </button>

                  <button
                    onClick={() => togglePlatform('ig')}
                    className={`relative p-4 rounded-xl border-2 transition-all flex flex-col items-center gap-2 ${
                      selectedPlatforms.includes('ig')
                        ? 'border-purple-500 bg-purple-50 text-purple-700'
                        : 'border-slate-200 hover:border-slate-300 text-slate-500'
                    }`}
                  >
                     <span className="text-2xl">📸</span>
                     <span className="font-bold text-sm">Instagram</span>
                     <span className="text-[10px] opacity-70">繁體 · 香港語氣</span>
                     {selectedPlatforms.includes('ig') && (
                       <div className="absolute top-2 right-2 w-2 h-2 rounded-full bg-purple-500"></div>
                     )}
                  </button>
                </div>
              </div>

              {/* Action Button */}
              <button
                onClick={handleGenerate}
                disabled={isGenerating || !topic.trim() || selectedPlatforms.length === 0}
                className={`w-full py-4 rounded-xl font-bold text-white shadow-lg shadow-purple-200 transition-all transform active:scale-[0.98] ${
                  isGenerating || !topic.trim() || selectedPlatforms.length === 0
                    ? 'bg-slate-400 cursor-not-allowed shadow-none'
                    : 'bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700'
                }`}
              >
                {isGenerating ? (
                  <span className="flex items-center justify-center gap-2">
                    <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    生成中 (Generating)...
                  </span>
                ) : (
                  "✨ 立即生成貼文"
                )}
              </button>
            </div>

            {/* Global Settings */}
            <SettingsPanel 
              bio={bio}
              setBio={setBio}
              addresses={addresses}
              setAddresses={setAddresses}
            />
          </div>

          {/* RIGHT COLUMN: Output */}
          <div className="lg:col-span-7">
            <div className="sticky top-24 space-y-6">
               <div className="flex items-center justify-between mb-2">
                 <h2 className="text-xl font-bold text-slate-800">
                   生成結果 (Results)
                 </h2>
                 {Object.keys(results).length > 0 && !isGenerating && (
                    <span className="text-xs text-green-600 bg-green-100 px-2 py-1 rounded">
                      ✅ 完成
                    </span>
                 )}
               </div>

               {Object.keys(results).length === 0 && !isGenerating ? (
                 <div className="border-2 border-dashed border-slate-200 rounded-2xl p-12 flex flex-col items-center justify-center text-slate-400 min-h-[400px] bg-white">
                   <span className="text-4xl mb-4">🚀</span>
                   <p className="text-lg font-medium">準備就緒</p>
                   <p className="text-sm">在左側輸入主題並點擊生成</p>
                 </div>
               ) : (
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                   {/* If only one platform is selected, make it span full width if needed, or stick to grid */}
                   {results.xhs && (
                     <div className={results.ig ? "col-span-1" : "col-span-1 md:col-span-2"}>
                       <OutputCard data={results.xhs} />
                     </div>
                   )}
                   {results.ig && (
                     <div className={results.xhs ? "col-span-1" : "col-span-1 md:col-span-2"}>
                       <OutputCard data={results.ig} />
                     </div>
                   )}
                 </div>
               )}
            </div>
          </div>

        </div>
      </main>
    </div>
  );
};

