import { GoogleGenAI } from "@google/genai";
import { Platform, StoreAddress, Tone } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Upgraded to Gemini 3 Pro for better reasoning and multimodal capabilities
const MODEL_NAME = "gemini-3-pro-preview";

const getToneInstructions = (tone: Tone): string => {
  switch (tone) {
    case 'professional':
      return `
      **語氣設定：專業權威 (Professional)**
      - 風格：專家視角，客觀冷靜，權威可信。
      - 重點：**深度挖掘用戶痛點 (Pain Points)**，並給出邏輯嚴密的解決方案。
      - 用詞：精準、高級、不廢話。
      - 適合場景：高單價產品、知識分享、行業分析。
      `;
    case 'warm':
      return `
      **語氣設定：溫暖親切 (Warm)**
      - 風格：像知心好友、閨蜜或鄰居。充滿同理心和生活氣息。
      - 重點：**情感共鳴 (Emotional Connection)**，描述美好生活場景，傳遞幸福感。
      - 用詞：溫柔、感性、治癒。
      - 適合場景：生活方式、家居、美食、情感類。
      `;
    case 'funny':
      return `
      **語氣設定：幽默有趣 (Funny)**
      - 風格：活潑跳脫，甚至帶點自嘲或搞怪。
      - 重點：**娛樂性 (Entertainment)**，讓讀者會心一笑或大笑。
      - 用詞：使用網絡潮語 (Internet Slang)、梗 (Memes)、誇張修辭。
      - 適合場景：年輕化品牌、快消品、娛樂話題。
      `;
    default:
      return "";
  }
};

const generatePromptText = (
  platform: Platform, 
  topic: string, 
  bio: string, 
  selectedAddresses: StoreAddress[],
  tone: Tone,
  hasImage: boolean
): string => {
  const addressList = selectedAddresses.length > 0 
    ? selectedAddresses.map(a => `${a.name}: ${a.detail}`).join('\n')
    : "不顯示地址 (No address selected)";

  const imageInstruction = hasImage 
    ? "**圖片分析指令：**\n請仔細分析附帶的圖片。描述圖片中的視覺細節（顏色、氛圍、產品特點、人物動作等），並將這些細節自然地融入到文案中，證明你是真的「看」到了這張圖，而不是憑空想像。" 
    : "**圖片說明：**\n用戶沒有提供圖片，請根據主題想像相關場景。";

  const toneInstruction = getToneInstructions(tone);

  if (platform === 'xhs') {
    return `
      你是一個頂級的小紅書內容創作者（KOL）。請根據以下要求撰寫一篇爆款筆記。

      **核心任務：**
      主題：${topic}
      ${imageInstruction}

      **品牌資訊：**
      1. 品牌簡介：${bio}
      2. 店鋪地址：${addressList}

      ${toneInstruction}

      **小紅書模式規則 (XHS Mode)：**
      1. **Emoji 策略**：必須使用**極其豐富**的 Emoji 🤩✨，每一段、甚至每一句重點都要有 Emoji 點綴，視覺上要色彩斑斕。
      2. **語言**：簡體中文 (Simplified Chinese)，內地網絡用語。
      3. **內容結構**：
         - **標題**：吸睛、懸念、或直接擊中利益點（加上 Emoji）。
         - **正文**：根據選定的語氣（${tone}）展開。必須包含品牌簡介和地址。
         - **標籤**：文末 5-10 個 Tag。

      **輸出格式：** 直接輸出標題和正文，不要解釋。
    `;
  } else {
    return `
      你是一個專業的 Instagram 社交媒體經理。請撰寫一個高互動率的 Post。

      **核心任務：**
      主題：${topic}
      ${imageInstruction}

      **品牌資訊：**
      1. 品牌簡介：${bio}
      2. 店鋪地址：${addressList}

      ${toneInstruction}

      **Instagram 模式規則 (IG Mode)：**
      1. **Emoji 策略**：適量但精準，用於強調情緒或分段，不像小紅書那麼密集，但要配合語氣。
      2. **語言**：繁體中文 (Traditional Chinese)，地道香港口語（如適用）。
      3. **內容結構**：
         - **Hook**：第一句決定生死。
         - **Body**：根據選定的語氣（${tone}）展開內容。
         - **CTA & Info**：清楚列出品牌簡介和地址。
         - **Hashtags**：文末 15-20 個 Tags，用空行或點點點隔開。

      **輸出格式：** 直接輸出貼文內容，不要解釋。
    `;
  }
};

export const generatePostContent = async (
  platform: Platform,
  topic: string,
  bio: string,
  addresses: StoreAddress[],
  tone: Tone,
  imageData?: { base64: string; mimeType: string } | null
): Promise<string> => {
  try {
    const selectedAddresses = addresses.filter(a => a.isSelected);
    const textPrompt = generatePromptText(platform, topic, bio, selectedAddresses, tone, !!imageData);

    let contents: any;

    if (imageData) {
      // Multimodal request: Text + Image
      contents = {
        parts: [
          {
            inlineData: {
              mimeType: imageData.mimeType,
              data: imageData.base64
            }
          },
          { text: textPrompt }
        ]
      };
    } else {
      // Text only request
      contents = textPrompt;
    }

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: contents,
      config: {
        temperature: tone === 'creative' ? 1 : 0.7, // Adjust temp slightly based on tone
        topK: 40,
        topP: 0.95,
      }
    });

    return response.text || "生成內容時發生錯誤，請重試。";
  } catch (error) {
    console.error(`Error generating content for ${platform}:`, error);
    throw new Error(`無法生成 ${platform === 'xhs' ? '小紅書' : 'Instagram'} 內容。請檢查網絡或稍後再試。`);
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Platform, StoreAddress, GeneratedContent, Tone, DEFAULT_BIO, DEFAULT_ADDRESSES } from './types';
import SettingsPanel from './components/SettingsPanel';
import OutputCard from './components/OutputCard';
import { generatePostContent } from './services/geminiService';

const App: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [selectedPlatforms, setSelectedPlatforms] = useState<Platform[]>(['xhs']);
  const [tone, setTone] = useState<Tone>('professional');
  const [bio, setBio] = useState(DEFAULT_BIO);
  const [addresses, setAddresses] = useState<StoreAddress[]>(DEFAULT_ADDRESSES);

  // Image State
  const [image, setImage] = useState<{ base64: string; mimeType: string; preview: string } | null>(null);

  const [results, setResults] = useState<{ xhs?: GeneratedContent; ig?: GeneratedContent }>({});
  const [isGenerating, setIsGenerating] = useState(false);

  // Paste Event Listener
  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      const items = e.clipboardData?.items;
      if (!items) return;

      for (const item of items) {
        if (item.type.startsWith('image/')) {
          const file = item.getAsFile();
          if (file) handleImageFile(file);
          break;
        }
      }
    };

    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, []);

  const handleImageFile = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const result = e.target?.result as string;
      const base64Data = result.split(',')[1];
      setImage({
        base64: base64Data,
        mimeType: file.type,
        preview: result
      });
    };
    reader.readAsDataURL(file);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      handleImageFile(e.target.files[0]);
    }
  };

  const removeImage = () => setImage(null);

  const togglePlatform = (p: Platform) => {
    setSelectedPlatforms(prev => 
      prev.includes(p) ? prev.filter(x => x !== p) : [...prev, p]
    );
  };

  const handleGenerate = async () => {
    if (!topic.trim()) return;
    if (selectedPlatforms.length === 0) return;

    setIsGenerating(true);

    const initialResults: { xhs?: GeneratedContent; ig?: GeneratedContent } = {};
    if (selectedPlatforms.includes('xhs')) {
      initialResults.xhs = { platform: 'xhs', content: '', loading: true };
    }
    if (selectedPlatforms.includes('ig')) {
      initialResults.ig = { platform: 'ig', content: '', loading: true };
    }
    setResults(initialResults);

    const promises = selectedPlatforms.map(async (platform) => {
      try {
        const content = await generatePostContent(
          platform, 
          topic, 
          bio, 
          addresses, 
          tone, 
          image ? { base64: image.base64, mimeType: image.mimeType } : null
        );
        setResults(prev => ({
          ...prev,
          [platform]: { platform, content, loading: false }
        }));
      } catch (e: any) {
        setResults(prev => ({
          ...prev,
          [platform]: { platform, content: '', loading: false, error: e.message || 'Error' }
        }));
      }
    });

    await Promise.all(promises);
    setIsGenerating(false);
  };

  const toneOptions: { value: Tone; label: string; icon: string; desc: string }[] = [
    { value: 'professional', label: '專業', icon: '👔', desc: '痛點與解決方案' },
    { value: 'warm', label: '溫暖', icon: '☕', desc: '親切感性' },
    { value: 'funny', label: '有趣', icon: '🤪', desc: '幽默有梗' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-gradient-to-br from-purple-600 to-pink-500 rounded-lg flex items-center justify-center text-white font-bold text-lg">
              S
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-800 to-slate-600">
              SocialGenius <span className="text-xs text-purple-600 font-normal bg-purple-50 px-2 py-0.5 rounded border border-purple-100">Pro</span>
            </h1>
          </div>
          <div className="text-xs font-medium px-3 py-1 bg-slate-100 rounded-full text-slate-500">
            v2.0 with Gemini Pro
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* LEFT COLUMN: Controls */}
          <div className="lg:col-span-5 space-y-6">

            {/* Input Card */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 space-y-6">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <span>📝</span> 創作中心 (Create)
              </h2>

              {/* Tone Slider */}
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-3">
                  語氣溫度 (Tone)
                </label>
                <div className="bg-slate-100 p-1 rounded-xl flex">
                  {toneOptions.map((option) => (
                    <button
                      key={option.value}
                      onClick={() => setTone(option.value)}
                      className={`flex-1 flex flex-col items-center justify-center py-2 px-1 rounded-lg text-sm transition-all duration-200 ${
                        tone === option.value
                          ? 'bg-white text-purple-700 shadow-sm font-semibold'
                          : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'
                      }`}
                    >
                      <span className="text-lg mb-0.5">{option.icon}</span>
                      <span>{option.label}</span>
                    </button>
                  ))}
                </div>
                <div className="mt-2 text-xs text-center text-slate-500">
                  當前模式：{toneOptions.find(t => t.value === tone)?.desc}
                </div>
              </div>

              {/* Topic Input */}
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">
                  貼文主題 / 產品賣點
                </label>
                <textarea
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  rows={3}
                  className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition text-base"
                  placeholder="例如：夏季最新款防曬乳，不黏膩，美白效果..."
                />
              </div>

              {/* Image Upload Area */}
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">
                  參考圖片 (Optional)
                </label>

                {!image ? (
                  <div 
                    className="border-2 border-dashed border-slate-300 rounded-xl p-6 text-center hover:bg-slate-50 transition cursor-pointer relative group"
                  >
                    <input 
                      type="file" 
                      accept="image/*" 
                      onChange={handleImageUpload}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="space-y-2 pointer-events-none">
                      <div className="mx-auto w-10 h-10 bg-purple-100 text-purple-500 rounded-full flex items-center justify-center group-hover:scale-110 transition-transform">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                      </div>
                      <p className="text-sm text-slate-600 font-medium">點擊上傳 或 Ctrl+V 貼上圖片</p>
                      <p className="text-xs text-slate-400">AI 將分析圖片細節生成文案</p>
                    </div>
                  </div>
                ) : (
                  <div className="relative rounded-xl overflow-hidden border border-slate-200 group">
                    <img src={image.preview} alt="Preview" className="w-full h-48 object-cover" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                       <button 
                         onClick={removeImage}
