export const generatePostContent = async (
  platform: Platform,
  topic: string,
  bio: string,
  addresses: StoreAddress[],
  tone: Tone,
  imageData?: { base64: string; mimeType: string } | null
): Promise<string> => {
  try {
    // Generate the standardized footer first
    const footer = generateFooter(platform, bio, addresses);

    // Pass the footer into the prompt so the AI knows it's coming, 
    // but we can also append it manually to be 100% sure if we wanted to. 
    // For now, letting AI handle the flow is better for tone consistency, 
    // but we instruct it strictly.
    const textPrompt = generatePromptText(platform, topic, footer, tone, !!imageData);

    let contents: any;

    if (imageData) {
      // Multimodal request: Text + Image
      contents = {
        parts: [
          {
            inlineData: {
              mimeType: imageData.mimeType,
              data: imageData.base64
            }
          },
          { text: textPrompt }
        ]
      };
    } else {
      // Text only request
      contents = textPrompt;
    }

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: contents,
      config: {
        temperature: tone === 'funny' ? 1 : 0.7, // Adjust temp slightly based on tone
        topK: 40,
        topP: 0.95,
      }
    });

    // Fallback: If for some reason the model hallucinates and forgets the footer (rare with this prompt),
    // you could force append it here. But let's trust Gemini 3 Pro first as it usually follows "Repeat this text" instructions well.
    // However, to be "Exactly" as requested, let's just return what the model gives, 
    // as it might integrate it better with newlines. 

    return response.text || "生成內容時發生錯誤，請重試。";
  } catch (error) {
    console.error(`Error generating content for ${platform}:`, error);
    throw new Error(`無法生成 ${platform === 'xhs' ? '小紅書' : 'Instagram'} 內容。請檢查網絡或稍後再試。`);
  }
};

