const generateSingleVariant = async (
  platform: Platform,
  topic: string,
  footer: string,
  tone: Tone,
  length: LengthLevel,
  variationIndex: number,
  imageData?: { base64: string; mimeType: string } | null
): Promise<string> => {
  const textPrompt = generatePromptText(platform, topic, footer, tone, length, variationIndex, !!imageData);

  let contents: any;
  if (imageData) {
    contents = {
      parts: [
        { inlineData: { mimeType: imageData.mimeType, data: imageData.base64 } },
        { text: textPrompt }
      ]
    };
  } else {
    contents = textPrompt;
  }

  const response = await ai.models.generateContent({
    model: MODEL_NAME,
    contents: contents,
    config: {
      temperature: 0.8 + (variationIndex * 0.1), // Variate temp slightly for second version
      topK: 40,
      topP: 0.95,
    }
  });

  return response.text || "生成內容時發生錯誤。";
};

export const generatePostContent = async (
  platform: Platform,
  topic: string,
  bio: string,
  addresses: StoreAddress[],
  tone: Tone,
  length: LengthLevel, // New parameter
  imageData?: { base64: string; mimeType: string } | null
): Promise<string[]> => {
  try {
    const footer = generateFooter(platform, bio, addresses);

    // Generate two variations in parallel
    const promises = [0, 1].map(index => 
      generateSingleVariant(platform, topic, footer, tone, length, index, imageData)
    );

    const results = await Promise.all(promises);
    return results;
  } catch (error) {
    console.error(`Error generating content for ${platform}:`, error);
    throw new Error(`無法生成 ${platform === 'xhs' ? '小紅書' : 'Instagram'} 內容。請檢查網絡或稍後再試。`);
  }
};

